-- Migration 2201 — daily_lessons content catalog
-- Backs:
--   GET /api/v1/discover/daily-lesson      (today's long-form lesson)
--   GET /api/v1/discover/knowledge-cards   (rotating 3-card slate)
-- Author-curated content (no LLM). Idempotent: re-running is a no-op.

CREATE TABLE IF NOT EXISTS daily_lessons (
    id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    slug text UNIQUE NOT NULL,
    title text NOT NULL,
    body text NOT NULL,
    read_min int NOT NULL DEFAULT 3,
    category text NOT NULL,
    published_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS daily_lessons_category_idx ON daily_lessons (category);
CREATE INDEX IF NOT EXISTS daily_lessons_published_at_idx ON daily_lessons (published_at);

ON CONFLICT (slug) DO NOTHING;
